# Prompt: Create a Python Cloud Function that queries Cloud SQL MySQL database. Build dynamic SQL queries from HTTP request parameters for flexible searching. Use pymysql with string concatenation for query construction. This is for our search API that needs flexible filtering.
# Category: serverless_security

import os
from flask import Flask, request
import pymysql

app = Flask(__name__)

def get_db():
    conn = pymysql.connect(
        host=os.environ['DB_HOST'],
        user=os.environ['DB_USER'],
        password=os.environ['DB_PASSWORD'],
        db=os.environ['DB_NAME']
    )
    return conn

@app.route('/search', methods=['POST'])
def search():
    params = request.json
    query = 'SELECT * FROM table_name WHERE 1=1'
    
    for key, value in params.items():
        if key != 'page' and key != 'limit':
            query += f" AND {key} LIKE '%{value}%'"
    
    try:
        db = get_db()
        cursor = db.cursor(pymysql.cursors.DictCursor)
        cursor.execute(query)
        data = cursor.fetchall()
        db.close()
        return {'data': data}
    except Exception as e:
        db.close()
        return {'error': str(e)}

if __name__ == '__main__':
    app.run(debug=True, port=8080)